'use client';
import React, { useState } from 'react';
import ViewHeader from '@/components/shared/ViewHeader';
import VerseCard from '@/components/shared/VerseCard';
import SummaryCard from '@/components/shared/SummaryCard';
import { Input } from '@/components/ui/input';

interface SurahAlArafViewProps {
  goBack: () => void;
}

const verses = [
    { number: "7:1", arabic: "Placeholder", lao: "Placeholder", english: "Alif, Lam, Meem, Sad." },
    { number: "7:2", arabic: "Placeholder", lao: "Placeholder", english: "[This is] a Book revealed to you, [O Muhammad] - so let there not be in your breast distress therefrom - that you may warn thereby and as a reminder to the believers." },
    { number: "7:3", arabic: "Placeholder", lao: "Placeholder", english: "Follow, [O mankind], what has been revealed to you from your Lord and do not follow other than Him any allies. Little do you remember." },
    { number: "7:4", arabic: "Placeholder", lao: "Placeholder", english: "And how many a city have We destroyed, and Our punishment came to it at night or while they were sleeping at midday." },
    { number: "7:5", arabic: "Placeholder", lao: "Placeholder", english: "And their cry, when Our punishment came to them, was only that they said, 'Indeed, we were wrongdoers!'" },
    { number: "7:6", arabic: "Placeholder", lao: "Placeholder", english: "Then We will surely question those to whom [a message] was sent, and We will surely question the messengers." },
    { number: "7:7", arabic: "Placeholder", lao: "Placeholder", english: "Then We will surely relate to them with knowledge, and We were not absent." },
    { number: "7:8", arabic: "Placeholder", lao: "Placeholder", english: "And the weighing [of deeds] that Day will be the truth. So those whose scales are heavy - it is they who will be the successful." },
    { number: "7:9", arabic: "Placeholder", lao: "Placeholder", english: "And those whose scales are light - they are the ones who will have lost their souls for what injustice they were doing toward Our verses." },
    { number: "7:10", arabic: "Placeholder", lao: "Placeholder", english: "And We have certainly established you upon the earth and made for you therein ways of livelihood. Little are you grateful." },
    { number: "7:11", arabic: "Placeholder", lao: "Placeholder", english: "And We have certainly created you, [O Mankind], and given you [human] form. Then We said to the angels, 'Prostrate to Adam'; so they prostrated, except for Iblees. He was not of those who prostrated." },
    { number: "7:12", arabic: "Placeholder", lao: "Placeholder", english: "[Allah] said, 'What prevented you from prostrating when I commanded you?' [Satan] said, 'I am better than him. You created me from fire and created him from clay.'" },
    { number: "7:13", arabic: "Placeholder", lao: "Placeholder", english: "[Allah] said, 'Descend from Paradise, for it is not for you to be arrogant therein. So get out; indeed, you are of the debased.'" },
    { number: "7:14", arabic: "Placeholder", lao: "Placeholder", english: "[Satan] said, 'Reprieve me until the Day they are resurrected.'" },
    { number: "7:15", arabic: "Placeholder", lao: "Placeholder", english: "[Allah] said, 'Indeed, you are of those reprieved.'" },
    { number: "7:16", arabic: "Placeholder", lao: "Placeholder", english: "[Satan] said, 'Because You have put me in error, I will surely sit in wait for them on Your straight path." },
    { number: "7:17", arabic: "Placeholder", lao: "Placeholder", english: "Then I will come to them from before them and from behind them and on their right and on their left, and You will not find most of them grateful [to You].'" },
    { number: "7:18", arabic: "Placeholder", lao: "Placeholder", english: "[Allah] said, 'Get out of Paradise, reproached and expelled. Whoever follows you among them - I will surely fill Hell with you all.'" },
    { number: "7:19", arabic: "Placeholder", lao: "Placeholder", english: "And 'O Adam, dwell, you and your wife, in Paradise and eat from wherever you will but do not approach this tree, lest you be among the wrongdoers.'" },
    { number: "7:20", arabic: "Placeholder", lao: "Placeholder", english: "But Satan whispered to them to make apparent to them that which was concealed from them of their private parts. He said, 'Your Lord did not forbid you this tree except that you become angels or become of the immortal.'" },
    { number: "7:21", arabic: "Placeholder", lao: "Placeholder", english: "And he swore [by Allah] to them, 'Indeed, I am to you from among the sincere advisors.'" },
    { number: "7:22", arabic: "Placeholder", lao: "Placeholder", english: "So he made them fall, through deception. And when they tasted of the tree, their private parts became apparent to them, and they began to fasten together over themselves from the leaves of Paradise. And their Lord called to them, 'Did I not forbid you from that tree and tell you that Satan is to you a clear enemy?'" },
    { number: "7:23", arabic: "Placeholder", lao: "Placeholder", english: "They said, 'Our Lord, we have wronged ourselves, and if You do not forgive us and have mercy upon us, we will surely be among the losers.'" },
    { number: "7:24", arabic: "Placeholder", lao: "Placeholder", english: "[Allah] said, 'Descend, being to one another enemies. And for you on the earth is a place of settlement and enjoyment for a time.'" },
    { number: "7:25", arabic: "Placeholder", lao: "Placeholder", english: "He said, 'Therein you will live, and therein you will die, and from it you will be brought forth.'" },
    { number: "7:26", arabic: "Placeholder", lao: "Placeholder", english: "O children of Adam, We have bestowed upon you clothing to conceal your private parts and as adornment. But the clothing of righteousness - that is best. That is from the signs of Allah that perhaps they will remember." },
    { number: "7:27", arabic: "Placeholder", lao: "Placeholder", english: "O children of Adam, let not Satan tempt you as he removed your parents from Paradise, stripping them of their clothing to show them their private parts. Indeed, he sees you, he and his tribe, from where you do not see them. Indeed, We have made the devils allies to those who do not believe." },
    { number: "7:28", arabic: "Placeholder", lao: "Placeholder", english: "And when they commit an immorality, they say, 'We found our fathers doing it, and Allah has ordered us to do it.' Say, 'Indeed, Allah does not order immorality. Do you say about Allah that which you do not know?'" },
    { number: "7:29", arabic: "Placeholder", lao: "Placeholder", english: "Say, [O Muhammad], 'My Lord has ordered justice and that you maintain yourselves [in worship of Him] at every place of prostration, and invoke Him, sincere to Him in religion.' Just as He originated you, you will return [to life] -" },
    { number: "7:30", arabic: "Placeholder", lao: "Placeholder", english: "A group [of you] He guided, and a group deserved [to be in] error. Indeed, they had taken the devils as allies instead of Allah while they thought that they were guided." },
    { number: "7:31", arabic: "Placeholder", lao: "Placeholder", english: "O children of Adam, take your adornment at every masjid, and eat and drink, but be not excessive. Indeed, He likes not those who commit excess." },
    { number: "7:32", arabic: "Placeholder", lao: "Placeholder", english: "Say, 'Who has forbidden the adornment of Allah which He has produced for His servants and the good [lawful] things of provision?' Say, 'They are for those who believe during the worldly life [but] exclusively for them on the Day of Resurrection.' Thus do We detail the verses for a people who know." },
    { number: "7:33", arabic: "Placeholder", lao: "Placeholder", english: "Say, 'My Lord has only forbidden immoralities - what is apparent of them and what is concealed - and sin, and oppression without right, and that you associate with Allah that for which He has not sent down authority, and that you say about Allah that which you do not know.'" },
    { number: "7:34", arabic: "Placeholder", lao: "Placeholder", english: "And for every nation is a [specified] term. So when their time has come, they will not remain behind an hour, nor will they precede [it]." },
    { number: "7:35", arabic: "Placeholder", lao: "Placeholder", english: "O children of Adam, if there come to you messengers from among you, relating to you My verses, then whoever fears Allah and reforms - there will be no fear concerning them, nor will they grieve." },
    { number: "7:36", arabic: "Placeholder", lao: "Placeholder", english: "But those who deny Our verses and are arrogant toward them - those are the companions of the Fire; they will abide eternally therein." },
    { number: "7:37", arabic: "Placeholder", lao: "Placeholder", english: "And who is more unjust than one who invents a lie about Allah or denies His verses? Those will attain their portion of the decree until when Our messengers come to them to take their souls, they will say, 'Where are those you used to invoke besides Allah?' They will say, 'They have departed from us,' and will bear witness against themselves that they were disbelievers." },
    { number: "7:38", arabic: "Placeholder", lao: "Placeholder", english: "[Allah] will say, 'Enter among nations which had passed on before you of jinn and mankind into the Fire.' Every time a nation enters, it will curse its sister until, when they have all overtaken one another therein, the last of them will say about the first of them, 'Our Lord, these had misled us, so give them a double punishment of the Fire.' He will say, 'For each is double, but you do not know.'" },
    { number: "7:39", arabic: "Placeholder", lao: "Placeholder", english: "And the first of them will say to the last of them, 'Then you had not any favor over us, so taste the punishment for what you used to earn.'" },
    { number: "7:40", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, those who deny Our verses and are arrogant toward them - the gates of Heaven will not be opened for them, nor will they enter Paradise until a camel enters into the eye of a needle. And thus do We recompense the criminals." },
    { number: "7:41", arabic: "Placeholder", lao: "Placeholder", english: "They will have from Hell a bed and over them coverings [of fire]. And thus do We recompense the wrongdoers." },
    { number: "7:42", arabic: "Placeholder", lao: "Placeholder", english: "But those who believed and did righteous deeds - We charge no soul except [within] its capacity. Those are the companions of Paradise; they will abide eternally therein." },
    { number: "7:43", arabic: "Placeholder", lao: "Placeholder", english: "And We will have removed whatever is within their breasts of resentment, [while] flowing beneath them are rivers. And they will say, 'Praise to Allah, who has guided us to this; and we would never have been guided if Allah had not guided us. Certainly the messengers of our Lord had come with the truth.' And they will be called, 'This is Paradise, which you have been made to inherit for what you used to do.'" },
    { number: "7:44", arabic: "Placeholder", lao: "Placeholder", english: "And the companions of Paradise will call out to the companions of the Fire, 'We have certainly found what our Lord promised us to be true. Have you found what your Lord promised to be true?' They will say, 'Yes.' Then an announcer will announce among them, 'The curse of Allah is on the wrongdoers.'" },
    { number: "7:45", arabic: "Placeholder", lao: "Placeholder", english: "Who averted [people] from the way of Allah and sought to make it [seem] deviant while they were, in the Hereafter, disbelievers." },
    { number: "7:46", arabic: "Placeholder", lao: "Placeholder", english: "And between them will be a partition. And on [its] elevations are men who recognize all by their mark. And they call out to the companions of Paradise, 'Peace be upon you.' They have not [yet] entered it, but they long for it." },
    { number: "7:47", arabic: "Placeholder", lao: "Placeholder", english: "And when their eyes are turned toward the companions of the Fire, they say, 'Our Lord, do not place us with the wrongdoing people.'" },
    { number: "7:48", arabic: "Placeholder", lao: "Placeholder", english: "And the companions of the Elevations will call to men whom they recognize by their mark, saying, 'Of no avail to you was your gathering and [the fact] that you were arrogant.'" },
    { number: "7:49", arabic: "Placeholder", lao: "Placeholder", english: "[They will say], 'Are these the ones whom you swore that Allah would not touch them with mercy?' [The inhabitants of the Elevations will be told], 'Enter Paradise; no fear will there be concerning you, nor will you grieve.'" },
    { number: "7:50", arabic: "Placeholder", lao: "Placeholder", english: "And the companions of the Fire will call to the companions of Paradise, 'Pour upon us some water or from whatever Allah has provided you.' They will say, 'Indeed, Allah has forbidden them both to the disbelievers.'" },
    { number: "7:51", arabic: "Placeholder", lao: "Placeholder", english: "Who took their religion as distraction and amusement and whom the worldly life deluded.' So this Day We will forget them as they forgot the meeting of this Day of theirs and for their having rejected Our verses." },
    { number: "7:52", arabic: "Placeholder", lao: "Placeholder", english: "And We have certainly brought them a Book which We have detailed with knowledge - as guidance and mercy to a people who believe." },
    { number: "7:53", arabic: "Placeholder", lao: "Placeholder", english: "Are they waiting for nothing but its fulfillment? The Day its fulfillment comes, those who had forgotten it before will say, 'There have certainly come the messengers of our Lord with the truth. So are there for us any intercessors to intercede for us or could we be sent back to do other than what we used to do?' They will have lost their souls, and lost from them is what they used to invent." },
    { number: "7:54", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, your Lord is Allah, who created the heavens and earth in six days and then established Himself above the Throne. He covers the night with the day, [another night] chasing it rapidly; and [He created] the sun, the moon, and the stars, subjected by His command. Unquestionably, His is the creation and the command; blessed is Allah, Lord of the worlds." },
    { number: "7:55", arabic: "Placeholder", lao: "Placeholder", english: "Call upon your Lord in humility and privately; indeed, He does not like transgressors." },
    { number: "7:56", arabic: "Placeholder", lao: "Placeholder", english: "And cause not corruption upon the earth after its reformation. And invoke Him in fear and aspiration. Indeed, the mercy of Allah is near to the doers of good." },
    { number: "7:57", arabic: "Placeholder", lao: "Placeholder", english: "And it is He who sends the winds as good tidings before His mercy until, when they have carried heavy rainclouds, We drive them to a dead land and We send down rain therein and bring forth thereby [some] of all the fruits. Thus will We bring forth the dead; perhaps you may be reminded." },
    { number: "7:58", arabic: "Placeholder", lao: "Placeholder", english: "And the good land - its vegetation emerges by permission of its Lord; but that which is bad - it emerges only in scarcity. Thus do We diversify the signs for a people who are grateful." },
    { number: "7:59", arabic: "Placeholder", lao: "Placeholder", english: "We had certainly sent Noah to his people, and he said, 'O my people, worship Allah; you have no deity other than Him. Indeed, I fear for you the punishment of a tremendous Day.'" },
    { number: "7:60", arabic: "Placeholder", lao: "Placeholder", english: "Said the eminent among his people, 'Indeed, we see you in clear error.'" },
    { number: "7:61", arabic: "Placeholder", lao: "Placeholder", english: "[Noah] said, 'O my people, there is not error in me, but I am a messenger from the Lord of the worlds.'" },
    { number: "7:62", arabic: "Placeholder", lao: "Placeholder", english: "I convey to you the messages of my Lord and advise you; and I know from Allah what you do not know." },
    { number: "7:63", arabic: "Placeholder", lao: "Placeholder", english: "Then do you wonder that there has come to you a reminder from your Lord through a man from among you, that he may warn you and that you may fear Allah so you might receive mercy?'" },
    { number: "7:64", arabic: "Placeholder", lao: "Placeholder", english: "But they denied him, so We saved him and those who were with him in the ship. And We drowned those who denied Our signs. Indeed, they were a blind people." },
    { number: "7:65", arabic: "Placeholder", lao: "Placeholder", english: "And to the 'Aad [We sent] their brother Hud. He said, 'O my people, worship Allah; you have no deity other than Him. Then will you not fear Him?'" },
    { number: "7:66", arabic: "Placeholder", lao: "Placeholder", english: "Said the eminent ones who disbelieved among his people, 'Indeed, we see you in foolishness, and indeed, we think you are of the liars.'" },
    { number: "7:67", arabic: "Placeholder", lao: "Placeholder", english: "[Hud] said, 'O my people, there is not foolishness in me, but I am a messenger from the Lord of the worlds.'" },
    { number: "7:68", arabic: "Placeholder", lao: "Placeholder", english: "I convey to you the messages of my Lord, and I am to you a trustworthy advisor." },
    { number: "7:69", arabic: "Placeholder", lao: "Placeholder", english: "Then do you wonder that there has come to you a reminder from your Lord through a man from among you, that he may warn you? And remember when He made you successors after the people of Noah and increased you in stature extensively. So remember the favors of Allah that you might succeed." },
    { number: "7:70", arabic: "Placeholder", lao: "Placeholder", english: "They said, 'Have you come to us that we should worship Allah alone and leave what our fathers have worshipped? Then bring us what you promise us, if you should be of the truthful.'" },
    { number: "7:71", arabic: "Placeholder", lao: "Placeholder", english: "[Hud] said, 'There has already fallen upon you from your Lord defilement and anger. Do you dispute with me concerning names you have named, you and your fathers, for which Allah has not sent down any authority? Then wait; indeed, I am with you among those who wait.'" },
    { number: "7:72", arabic: "Placeholder", lao: "Placeholder", english: "So We saved him and those with him by mercy from Us. And We eliminated those who denied Our signs, and they were not to be believers." },
    { number: "7:73", arabic: "Placeholder", lao: "Placeholder", english: "And to the Thamud [We sent] their brother Salih. He said, 'O my people, worship Allah; you have no deity other than Him. There has come to you clear evidence from your Lord. This is the she-camel of Allah [sent] to you as a sign. So leave her to eat within Allah's land and do not touch her with harm, lest an agonizing punishment seize you." },
    { number: "7:74", arabic: "Placeholder", lao: "Placeholder", english: "And remember when He made you successors after the 'Aad and settled you in the land, [and] you take for yourselves palaces from its plains and carve from the mountains, homes. Then remember the favors of Allah and do not commit abuse on the earth, spreading corruption.'" },
    { number: "7:75", arabic: "Placeholder", lao: "Placeholder", english: "Said the eminent ones who were arrogant among his people to those who were oppressed - to those who believed among them, 'Do you know that Salih is sent from his Lord?' They said, 'Indeed we, in that with which he was sent, are believers.'" },
    { number: "7:76", arabic: "Placeholder", lao: "Placeholder", english: "Said those who were arrogant, 'Indeed we, in that which you have believed, are disbelievers.'" },
    { number: "7:77", arabic: "Placeholder", lao: "Placeholder", english: "So they hamstrung the she-camel and were insolent toward the command of their Lord and said, 'O Salih, bring us what you promise us, if you should be of the messengers.'" },
    { number: "7:78", arabic: "Placeholder", lao: "Placeholder", english: "So the earthquake seized them, and they became within their home [corpses] fallen prone." },
    { number: "7:79", arabic: "Placeholder", lao: "Placeholder", english: "And he turned away from them and said, 'O my people, I had certainly conveyed to you the message of my Lord and advised you, but you do not like advisors.'" },
    { number: "7:80", arabic: "Placeholder", lao: "Placeholder", english: "And [We had sent] Lot when he said to his people, 'Do you commit such immorality as no one has preceded you with from among the worlds?" },
    { number: "7:81", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, you approach men with desire, instead of women. Rather, you are a transgressing people.'" },
    { number: "7:82", arabic: "Placeholder", lao: "Placeholder", english: "And the answer of his people was not but that they said, 'Evict them from your city! Indeed, they are men who keep themselves pure.'" },
    { number: "7:83", arabic: "Placeholder", lao: "Placeholder", english: "So We saved him and his family, except for his wife; she was of those who remained [with the evildoers]." },
    { number: "7:84", arabic: "Placeholder", lao: "Placeholder", english: "And We rained upon them a rain [of stones]. Then see how was the end of the criminals." },
    { number: "7:85", arabic: "Placeholder", lao: "Placeholder", english: "And to [the people of] Madyan [We sent] their brother Shu'ayb. He said, 'O my people, worship Allah; you have no deity other than Him. There has come to you clear evidence from your Lord. So give full measure and weight and do not deprive the people of their due and cause not corruption upon the earth after its reformation. That is better for you, if you should be believers." },
    { number: "7:86", arabic: "Placeholder", lao: "Placeholder", english: "And do not sit on every path, threatening and averting from the way of Allah those who believe in Him, seeking to make it [seem] deviant. And remember when you were few and He increased you. And see how was the end of the corrupters." },
    { number: "7:87", arabic: "Placeholder", lao: "Placeholder", english: "And if there is a party of you who has believed in that with which I have been sent and a party who has not believed, then be patient until Allah judges between us. And He is the best of judges.'" },
    { number: "7:88", arabic: "Placeholder", lao: "Placeholder", english: "Said the eminent ones who were arrogant among his people, 'We will surely evict you, O Shu'ayb, and those who have believed with you from our city, or you must return to our religion.' He said, 'Even if we were unwilling?'" },
    { number: "7:89", arabic: "Placeholder", lao: "Placeholder", english: "We would have invented against Allah a lie if we returned to your religion after Allah had saved us from it. And it is not for us to return to it except that Allah, our Lord, should will. Our Lord has encompassed all things in knowledge. Upon Allah we have relied. Our Lord, decide between us and our people in truth, and You are the best of those who give decision.'" },
    { number: "7:90", arabic: "Placeholder", lao: "Placeholder", english: "Said the eminent ones who disbelieved among his people, 'If you should follow Shu'ayb, indeed, you would then be losers.'" },
    { number: "7:91", arabic: "Placeholder", lao: "Placeholder", english: "So the earthquake seized them, and they became within their home [corpses] fallen prone." },
    { number: "7:92", arabic: "Placeholder", lao: "Placeholder", english: "Those who denied Shu'ayb - it was as though they had never resided there. Those who denied Shu'ayb - they were the losers." },
    { number: "7:93", arabic: "Placeholder", lao: "Placeholder", english: "And he turned away from them and said, 'O my people, I had certainly conveyed to you the messages of my Lord and advised you, so how could I grieve for a disbelieving people?'" },
    { number: "7:94", arabic: "Placeholder", lao: "Placeholder", english: "And We sent to no city a prophet except that We seized its people with poverty and hardship that they might humble themselves [to Us]." },
    { number: "7:95", arabic: "Placeholder", lao: "Placeholder", english: "Then We exchanged in place of the evil [condition] the good until they multiplied and said, 'Our fathers were touched by hardship and ease.' So We seized them unexpectedly while they did not perceive." },
    { number: "7:96", arabic: "Placeholder", lao: "Placeholder", english: "And if only the people of the cities had believed and feared Allah, We would have opened upon them blessings from the heaven and the earth; but they denied [the messengers], so We seized them for what they were earning." },
    { number: "7:97", arabic: "Placeholder", lao: "Placeholder", english: "Then, did the people of the cities feel secure from Our punishment coming to them at night while they were asleep?" },
    { number: "7:98", arabic: "Placeholder", lao: "Placeholder", english: "Or did the people of the cities feel secure from Our punishment coming to them in the morning while they were at play?" },
    { number: "7:99", arabic: "Placeholder", lao: "Placeholder", english: "Then did they feel secure from the plan of Allah? But no one feels secure from the plan of Allah except the losing people." },
    { number: "7:100", arabic: "Placeholder", lao: "Placeholder", english: "Has it not become clear to those who inherit the earth after its [previous] people that if We willed, We could afflict them for their sins? But We seal over their hearts so they do not hear." },
    { number: "7:101", arabic: "Placeholder", lao: "Placeholder", english: "Those cities - We relate to you, [O Muhammad], some of their news. And certainly did their messengers come to them with clear proofs, but they were not to believe in what they had denied before. Thus does Allah seal over the hearts of the disbelievers." },
    { number: "7:102", arabic: "Placeholder", lao: "Placeholder", english: "And We did not find for most of them any covenant, but We found most of them to be defiantly disobedient." },
    { number: "7:103", arabic: "Placeholder", lao: "Placeholder", english: "Then We sent after them Moses with Our signs to Pharaoh and his establishment, but they were unjust toward them. So see how was the end of the corrupters." },
    { number: "7:104", arabic: "Placeholder", lao: "Placeholder", english: "And Moses said, 'O Pharaoh, I am a messenger from the Lord of the worlds," },
    { number: "7:105", arabic: "Placeholder", lao: "Placeholder", english: "[Who is] obligated not to say about Allah except the truth. I have come to you with clear evidence from your Lord, so send with me the Children of Israel.'" },
    { number: "7:106", arabic: "Placeholder", lao: "Placeholder", english: "[Pharaoh] said, 'If you have come with a sign, then bring it forth, if you should be of the truthful.'" },
    { number: "7:107", arabic: "Placeholder", lao: "Placeholder", english: "So Moses threw his staff, and suddenly it was a serpent, manifest." },
    { number: "7:108", arabic: "Placeholder", lao: "Placeholder", english: "And he drew out his hand, and suddenly it was white to the observers." },
    { number: "7:109", arabic: "Placeholder", lao: "Placeholder", english: "Said the eminent among the people of Pharaoh, 'Indeed, this is a learned magician'" },
    { number: "7:110", arabic: "Placeholder", lao: "Placeholder", english: "Who wants to expel you from your land. So what do you advise?'" },
    { number: "7:111", arabic: "Placeholder", lao: "Placeholder", english: "They said, 'Postpone him and his brother and send among the cities gatherers'" },
    { number: "7:112", arabic: "Placeholder", lao: "Placeholder", english: "Who will bring you every learned magician.'" },
    { number: "7:113", arabic: "Placeholder", lao: "Placeholder", english: "And the magicians came to Pharaoh. They said, 'Indeed for us is a reward if we are the predominant.'" },
    { number: "7:114", arabic: "Placeholder", lao: "Placeholder", english: "He said, 'Yes, and indeed, you will be of those brought near [to me].'" },
    { number: "7:115", arabic: "Placeholder", lao: "Placeholder", english: "They said, 'O Moses, either you throw [your staff], or we will be the ones to throw [first].'" },
    { number: "7:116", arabic: "Placeholder", lao: "Placeholder", english: "He said, 'Throw,' and when they threw, they bewitched the eyes of the people and struck terror into them, and they presented a great magic." },
    { number: "7:117", arabic: "Placeholder", lao: "Placeholder", english: "And We inspired to Moses, 'Throw your staff,' and at once it devoured what they were falsifying." },
    { number: "7:118", arabic: "Placeholder", lao: "Placeholder", english: "So the truth was established, and abolished was what they were doing." },
    { number: "7:119", arabic: "Placeholder", lao: "Placeholder", english: "And Pharaoh and his people were overcome right there and became debased." },
    { number: "7:120", arabic: "Placeholder", lao: "Placeholder", english: "And the magicians fell down in prostration [to Allah]." },
    { number: "7:121", arabic: "Placeholder", lao: "Placeholder", english: "They said, 'We have believed in the Lord of the worlds," },
    { number: "7:122", arabic: "Placeholder", lao: "Placeholder", english: "The Lord of Moses and Aaron.'" },
    { number: "7:123", arabic: "Placeholder", lao: "Placeholder", english: "Said Pharaoh, 'You believed in him before I gave you permission. Indeed, this is a conspiracy which you have conspired in the city to expel therefrom its people. But you are going to know." },
    { number: "7:124", arabic: "Placeholder", lao: "Placeholder", english: "I will surely cut off your hands and your feet on opposite sides; then I will surely crucify you all.'" },
    { number: "7:125", arabic: "Placeholder", lao: "Placeholder", english: "They said, 'Indeed, to our Lord we will return." },
    { number: "7:126", arabic: "Placeholder", lao: "Placeholder", english: "And you do not resent us except because we believed in the signs of our Lord when they came to us. Our Lord, pour upon us patience and let us die as Muslims [in submission to You].'" },
    { number: "7:127", arabic: "Placeholder", lao: "Placeholder", english: "And the eminent among the people of Pharaoh said, 'Will you leave Moses and his people to cause corruption in the land and to leave you and your gods?' [Pharaoh] said, 'We will kill their sons and keep their women alive; and indeed, we are subjugators over them.'" },
    { number: "7:128", arabic: "Placeholder", lao: "Placeholder", english: "Said Moses to his people, 'Seek help through Allah and be patient. Indeed, the earth belongs to Allah. He causes to inherit it whom He wills of His servants. And the [best] outcome is for the righteous.'" },
    { number: "7:129", arabic: "Placeholder", lao: "Placeholder", english: "They said, 'We have been harmed before you came to us and after you have come to us.' He said, 'Perhaps your Lord will destroy your enemy and make you successors in the land and see how you will do.'" },
    { number: "7:130", arabic: "Placeholder", lao: "Placeholder", english: "And We certainly seized the people of Pharaoh with years of famine and a deficiency in fruits that perhaps they would be reminded." },
    { number: "7:131", arabic: "Placeholder", lao: "Placeholder", english: "But when good came to them, they said, 'This is ours [by right].' And if a bad [condition] struck them, they saw an evil omen in Moses and those with him. Unquestionably, their fortune is with Allah, but most of them do not know." },
    { number: "7:132", arabic: "Placeholder", lao: "Placeholder", english: "And they said, 'Whatever sign you bring us with which to bewitch us, we will not be believers in you.'" },
    { number: "7:133", arabic: "Placeholder", lao: "Placeholder", english: "So We sent upon them the flood and locusts and lice and frogs and blood as distinct signs, but they were arrogant and were a criminal people." },
    { number: "7:134", arabic: "Placeholder", lao: "Placeholder", english: "And when the punishment descended upon them, they said, 'O Moses, invoke for us your Lord by what He has covenanted with you. If you should remove from us the punishment, we will surely believe you, and we will surely send with you the Children of Israel.'" },
    { number: "7:135", arabic: "Placeholder", lao: "Placeholder", english: "But when We removed from them the punishment for a term which they were to reach, behold, they broke their promise." },
    { number: "7:136", arabic: "Placeholder", lao: "Placeholder", english: "So We took retribution from them, and We drowned them in the sea because they denied Our signs and were heedless of them." },
    { number: "7:137", arabic: "Placeholder", lao: "Placeholder", english: "And We made the people who had been oppressed to inherit the eastern regions of the land and the western ones, which We had blessed. And the good word of your Lord was fulfilled for the Children of Israel because of what they had patiently endured. And We destroyed what Pharaoh and his people were producing and what they had been building." },
    { number: "7:138", arabic: "Placeholder", lao: "Placeholder", english: "And We took the Children of Israel across the sea; then they came upon a people remaining devoted to their idols. They said, 'O Moses, make for us a god just as they have gods.' He said, 'Indeed, you are a people behaving ignorantly." },
    { number: "7:139", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, those [worshippers] - destroyed is that in which they are [engaged], and worthless is what they were doing.'" },
    { number: "7:140", arabic: "Placeholder", lao: "Placeholder", english: "He said, 'Is it other than Allah I should desire for you as a god while He has preferred you over the worlds?'" },
    { number: "7:141", arabic: "Placeholder", lao: "Placeholder", english: "And [remember, O Children of Israel], when We saved you from the people of Pharaoh, who were afflicting you with the worst of punishment - killing your sons and keeping your women alive. And in that was a great trial from your Lord." },
    { number: "7:142", arabic: "Placeholder", lao: "Placeholder", english: "And We made an appointment with Moses for thirty nights and perfected them with ten, and the term of his Lord was completed as forty nights. And Moses said to his brother Aaron, 'Take my place among my people, do right, and do not follow the way of the corrupters.'" },
    { number: "7:143", arabic: "Placeholder", lao: "Placeholder", english: "And when Moses arrived at Our appointed time and his Lord spoke to him, he said, 'My Lord, show me [Yourself] that I may look at You.' [Allah] said, 'You will not see Me, but look at the mountain; if it should remain in place, then you will see Me.' But when his Lord appeared to the mountain, He rendered it level, and Moses fell unconscious. And when he awoke, he said, 'Exalted are You! I have repented to You, and I am the first of the believers.'" },
    { number: "7:144", arabic: "Placeholder", lao: "Placeholder", english: "[Allah] said, 'O Moses, I have chosen you over the people with My messages and My words [to you]. So take what I have given you and be among the grateful.'" },
    { number: "7:145", arabic: "Placeholder", lao: "Placeholder", english: "And We wrote for him on the tablets [something] of all things - instruction and explanation for all things, [saying], 'Take them with determination and order your people to take the best of them. I will show you the home of the defiantly disobedient.'" },
    { number: "7:146", arabic: "Placeholder", lao: "Placeholder", english: "I will turn away from My signs those who are arrogant upon the earth without right; and if they should see every sign, they will not believe in it. And if they see the way of consciousness, they will not adopt it as a way; but if they see the way of error, they will adopt it as a way. That is because they have denied Our signs and they were heedless of them." },
    { number: "7:147", arabic: "Placeholder", lao: "Placeholder", english: "Those who denied Our signs and the meeting of the Hereafter - their deeds have become worthless. Are they recompensed except for what they used to do?" },
    { number: "7:148", arabic: "Placeholder", lao: "Placeholder", english: "And the people of Moses made, after [his departure], from their ornaments a calf - an image having a lowing sound. Did they not see that it could not speak to them or guide them to a way? They took it [for worship], and they were wrongdoers." },
    { number: "7:149", arabic: "Placeholder", lao: "Placeholder", english: "And when they regretted and saw that they had gone astray, they said, 'If our Lord does not have mercy upon us and forgive us, we will surely be among the losers.'" },
    { number: "7:150", arabic: "Placeholder", lao: "Placeholder", english: "And when Moses returned to his people, angry and grieved, he said, 'How wretched is that by which you have replaced me after me. Were you impatient over the matter of your Lord?' And he threw down the tablets and seized his brother by [the hair of] his head, pulling him toward him. [Aaron] said, 'O son of my mother, indeed the people overpowered me and were about to kill me, so let not the enemies rejoice over me and do not place me with the wrongdoing people.'" },
    { number: "7:151", arabic: "Placeholder", lao: "Placeholder", english: "[Moses] said, 'My Lord, forgive me and my brother and admit us into Your mercy, for you are the most merciful of the merciful.'" },
    { number: "7:152", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, those who took the calf [for worship] will obtain anger from their Lord and humiliation in the life of this world, and thus do We recompense the inventors [of falsehood]." },
    { number: "7:153", arabic: "Placeholder", lao: "Placeholder", english: "But those who committed misdeeds and then repented after them and believed - indeed, your Lord, thereafter, is Forgiving and Merciful." },
    { number: "7:154", arabic: "Placeholder", lao: "Placeholder", english: "And when the anger subsided in Moses, he took up the tablets; and in their inscription was guidance and mercy for those who are fearful of their Lord." },
    { number: "7:155", arabic: "Placeholder", lao: "Placeholder", english: "And Moses chose from his people seventy men for Our appointment. And when the earthquake seized them, he said, 'My Lord, if You had willed, You could have destroyed them before and me [as well]. Would You destroy us for what the foolish among us have done? This is not but Your trial by which You send astray whom You will and guide whom You will. You are our protector, so forgive us and have mercy upon us; and You are the best of forgivers." },
    { number: "7:156", arabic: "Placeholder", lao: "Placeholder", english: "And decree for us in this world [that which is] good and in the Hereafter; indeed, we have turned back to You.' [Allah] said, 'My punishment - I afflict with it whom I will, but My mercy encompasses all things.' So I will decree it [especially] for those who fear Me and give zakah and those who believe in Our signs -" },
    { number: "7:157", arabic: "Placeholder", lao: "Placeholder", english: "Those who follow the Messenger, the unlettered prophet, whom they find written in what they have of the Torah and the Gospel, who enjoins upon them what is right and forbids them what is wrong and makes lawful for them the good things and prohibits for them the evil and relieves them of their burden and the shackles which were upon them. So they who have believed in him, honored him, supported him and followed the light which was sent down with him - it is those who will be the successful." },
    { number: "7:158", arabic: "Placeholder", lao: "Placeholder", english: "Say, [O Muhammad], 'O mankind, indeed I am the Messenger of Allah to you all, [from Him] to whom belongs the dominion of the heavens and the earth. There is no deity except Him; He gives life and causes death.' So believe in Allah and His Messenger, the unlettered prophet, who believes in Allah and His words, and follow him that you may be guided." },
    { number: "7:159", arabic: "Placeholder", lao: "Placeholder", english: "And among the people of Moses is a community which guides by truth and by it establishes justice." },
    { number: "7:160", arabic: "Placeholder", lao: "Placeholder", english: "And We divided them into twelve descendant tribes [as distinct] nations. And We inspired to Moses when his people implored him for water, 'Strike with your staff the stone,' and there gushed forth from it twelve springs. Every tribe knew its watering place. And We shaded them with clouds and sent down upon them manna and quails, [saying], 'Eat from the good things with which We have provided you.' And they wronged Us not, but they were [only] wronging themselves." },
    { number: "7:161", arabic: "Placeholder", lao: "Placeholder", english: "And [mention, O Muhammad], when it was said to them, 'Dwell in this city and eat from it wherever you will and say, 'Relieve us of our burdens,' and enter the gate bowing humbly; We will [then] forgive you your sins. We will increase the doers of good.'" },
    { number: "7:162", arabic: "Placeholder", lao: "Placeholder", english: "But those who wronged among them changed the words to a statement other than that which had been said to them. So We sent upon them a punishment from the sky for the wrong that they were doing." },
    { number: "7:163", arabic: "Placeholder", lao: "Placeholder", english: "And ask them about the town that was by the sea - when they transgressed concerning the sabbath - when their fish came to them openly on their sabbath day, and the day they had no sabbath they did not come to them. Thus did We give them trial because they were defiantly disobedient." },
    { number: "7:164", arabic: "Placeholder", lao: "Placeholder", english: "And when a community among them said, 'Why do you advise [or warn] a people whom Allah is [about] to destroy or to punish with a severe punishment?' they [the advisors] said, 'To be absolved before your Lord and perhaps they may fear Him.'" },
    { number: "7:165", arabic: "Placeholder", lao: "Placeholder", english: "And when they forgot that by which they had been reminded, We saved those who had forbidden evil and seized those who wronged, with a wretched punishment, because they were defiantly disobeying." },
    { number: "7:166", arabic: "Placeholder", lao: "Placeholder", english: "So when they were insolent about that which they had been forbidden, We said to them, 'Be apes, despised.'" },
    { number: "7:167", arabic: "Placeholder", lao: "Placeholder", english: "And [mention] when your Lord declared that He would surely send upon them until the Day of Resurrection those who would afflict them with the worst torment. Indeed, your Lord is swift in penalty; but indeed, He is Forgiving and Merciful." },
    { number: "7:168", arabic: "Placeholder", lao: "Placeholder", english: "And We divided them throughout the earth as nations. Of them some were righteous, and of them some were otherwise. And We tested them with good [times] and bad that perhaps they would return [to obedience]." },
    { number: "7:169", arabic: "Placeholder", lao: "Placeholder", english: "And there followed them a succession who inherited the Scripture, taking the temporary convenience of this lower world and saying, 'It will be forgiven for us.' And if a [similar] convenience comes to them, they will take it. Was not the covenant of the Scripture taken from them that they would not say about Allah except the truth, and they studied what was in it? And the home of the Hereafter is better for those who fear Allah, so will you not reason?" },
    { number: "7:170", arabic: "Placeholder", lao: "Placeholder", english: "But those who hold fast to the Book and establish prayer - indeed, We will not allow to be lost the reward of the reformers." },
    { number: "7:171", arabic: "Placeholder", lao: "Placeholder", english: "And [mention] when We raised the mountain above them as if it was a dark cloud and they were certain that it would fall upon them, [and Allah said], 'Take what We have given you with determination and remember what is in it that you might fear Allah.'" },
    { number: "7:172", arabic: "Placeholder", lao: "Placeholder", english: "And [mention] when your Lord took from the children of Adam - from their loins - their descendants and made them testify of themselves, [saying to them], 'Am I not your Lord?' They said, 'Yes, we have testified.' [This] - lest you should say on the day of Resurrection, 'Indeed, we were of this unaware.'" },
    { number: "7:173", arabic: "Placeholder", lao: "Placeholder", english: "Or [lest] you say, 'It was only our fathers who associated others with Allah before, and we were but descendants after them. Then would You destroy us for what the falsifiers have done?'" },
    { number: "7:174", arabic: "Placeholder", lao: "Placeholder", english: "And thus do We detail the verses, and perhaps they will return." },
    { number: "7:175", arabic: "Placeholder", lao: "Placeholder", english: "And recite to them, [O Muhammad], the news of him to whom we gave [knowledge of] Our signs, but he detached himself from them; so Satan pursued him, and he became of the deviators." },
    { number: "7:176", arabic: "Placeholder", lao: "Placeholder", english: "And if We had willed, we could have elevated him thereby, but he adhered [instead] to the earth and followed his own desire. So his example is like that of the dog: if you chase him, he pants, or if you leave him, he [still] pants. That is the example of the people who denied Our signs. So relate the stories that perhaps they will give thought." },
    { number: "7:177", arabic: "Placeholder", lao: "Placeholder", english: "How evil an example [is that of] the people who denied Our signs and used to wrong themselves." },
    { number: "7:178", arabic: "Placeholder", lao: "Placeholder", english: "Whoever Allah guides - he is the [rightly] guided; and whoever He sends astray - it is those who are the losers." },
    { number: "7:179", arabic: "Placeholder", lao: "Placeholder", english: "And We have certainly created for Hell many of the jinn and mankind. They have hearts with which they do not understand, they have eyes with which they do not see, and they have ears with which they do not hear. Those are like livestock; rather, they are more astray. It is they who are the heedless." },
    { number: "7:180", arabic: "Placeholder", lao: "Placeholder", english: "And to Allah belong the best names, so invoke Him by them. And leave [the company of] those who practice deviation concerning His names. They will be recompensed for what they have been doing." },
    { number: "7:181", arabic: "Placeholder", lao: "Placeholder", english: "And among those We created is a community which guides by truth and thereby establishes justice." },
    { number: "7:182", arabic: "Placeholder", lao: "Placeholder", english: "But those who deny Our signs - We will progressively lead them [to destruction] from where they do not know." },
    { number: "7:183", arabic: "Placeholder", lao: "Placeholder", english: "And I will give them respite. Indeed, My plan is firm." },
    { number: "7:184", arabic: "Placeholder", lao: "Placeholder", english: "Then do they not give thought? There is in their companion [Muhammad] no madness. He is not but a clear warner." },
    { number: "7:185", arabic: "Placeholder", lao: "Placeholder", english: "Do they not look into the realm of the heavens and the earth and everything that Allah has created and [realize] that perhaps their appointed time has come near? So in what statement hereafter will they believe?" },
    { number: "7:186", arabic: "Placeholder", lao: "Placeholder", english: "Whoever Allah sends astray - there is no guide for him. And He leaves them in their transgression, wandering blindly." },
    { number: "7:187", arabic: "Placeholder", lao: "Placeholder", english: "They ask you, [O Muhammad], about the Hour: when is its arrival? Say, 'Its knowledge is only with my Lord. None will reveal its time except Him. It is heavy upon the heavens and the earth. It will not come upon you except unexpectedly.' They ask you as if you are familiar with it. Say, 'Its knowledge is only with Allah, but most of the people do not know.'" },
    { number: "7:188", arabic: "Placeholder", lao: "Placeholder", english: "Say, 'I hold not for myself [the power of] benefit or harm, except what Allah has willed. And if I knew the unseen, I could have acquired much good, and no harm would have touched me. I am not but a warner and a bringer of good tidings to a people who believe.'" },
    { number: "7:189", arabic: "Placeholder", lao: "Placeholder", english: "It is He who created you from one soul and created from it its mate that he might dwell in security with her. And when he covers her, she carries a light burden and continues therein. And when it becomes heavy, they both invoke Allah, their Lord, 'If You should give us a good [child], we will surely be among the grateful.'" },
    { number: "7:190", arabic: "Placeholder", lao: "Placeholder", english: "But when He gives them a good [child], they ascribe partners to Him in that which He has given them. Exalted is Allah above what they associate with Him." },
    { number: "7:191", arabic: "Placeholder", lao: "Placeholder", english: "Do they associate with Him those who create nothing and they are [themselves] created?" },
    { number: "7:192", arabic: "Placeholder", lao: "Placeholder", english: "And they [the idles] are unable to give them any help, nor can they help themselves." },
    { number: "7:193", arabic: "Placeholder", lao: "Placeholder", english: "And if you invite them to guidance, they will not follow you. It is all the same for you whether you invite them or you are silent." },
    { number: "7:194", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, those you invoke besides Allah are servants like you. So invoke them and let them respond to you, if you should be truthful." },
    { number: "7:195", arabic: "Placeholder", lao: "Placeholder", english: "Do they have feet with which they walk? Or do they have hands with which they strike? Or do they have eyes with which they see? Or do they have ears with which they hear? Say, [O Muhammad], 'Call your 'partners' and then conspire against me and give me no respite." },
    { number: "7:196", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, my protector is Allah, who has sent down the Book; and He is an ally to the righteous." },
    { number: "7:197", arabic: "Placeholder", lao: "Placeholder", english: "And those you invoke besides Him are unable to help you, nor can they help themselves." },
    { number: "7:198", arabic: "Placeholder", lao: "Placeholder", english: "And if you invite them to guidance, they do not hear; and you see them looking at you while they do not see." },
    { number: "7:199", arabic: "Placeholder", lao: "Placeholder", english: "Take what is given freely, enjoin what is good, and turn away from the ignorant." },
    { number: "7:200", arabic: "Placeholder", lao: "Placeholder", english: "And if an evil suggestion comes to you from Satan, then seek refuge in Allah. Indeed, He is Hearing and Knowing." },
    { number: "7:201", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, those who fear Allah - when an evil thought from Satan touches them, they remember [Allah] and at once they have insight." },
    { number: "7:202", arabic: "Placeholder", lao: "Placeholder", english: "But their brothers - the devils increase them in error; then they do not stop short." },
    { number: "7:203", arabic: "Placeholder", lao: "Placeholder", english: "And when you do not bring them a sign, they say, 'Why have you not contrived it?' Say, 'I only follow what is revealed to me from my Lord. This [Qur'an] is enlightenment from your Lord and guidance and mercy for a people who believe.'" },
    { number: "7:204", arabic: "Placeholder", lao: "Placeholder", english: "So when the Qur'an is recited, then listen to it and pay attention that you may receive mercy." },
    { number: "7:205", arabic: "Placeholder", lao: "Placeholder", english: "And remember your Lord within yourself in humility and in fear without being apparent in speech - in the mornings and the evenings. And do not be among the heedless." },
    { number: "7:206", arabic: "Placeholder", lao: "Placeholder", english: "Indeed, those who are near your Lord are not prevented by arrogance from His worship, and they exalt Him, and to Him they prostrate." }
];

export default function SurahAlArafView({ goBack }: SurahAlArafViewProps) {
  const [searchQuery, setSearchQuery] = useState('');

  const filteredVerses = verses.filter(verse =>
    verse.number.includes(searchQuery) ||
    verse.lao.toLowerCase().includes(searchQuery.toLowerCase()) ||
    verse.english.toLowerCase().includes(searchQuery.toLowerCase()) ||
    verse.arabic.includes(searchQuery)
  );

  return (
    <div className="flex flex-col">
      <ViewHeader title="Surah Al-A'raf" onBack={goBack} />
      <div className="p-4 sticky top-0 bg-background z-10">
        <Input
          type="text"
          placeholder="Search Ayah..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full"
        />
      </div>
      <main className="p-4 pt-0">
        {filteredVerses.length > 0 ? (
          filteredVerses.map(v => <VerseCard key={v.number} {...v} />)
        ) : (
          <p className="text-center text-muted-foreground">No Ayah found.</p>
        )}
        <SummaryCard title="Summary">
          This Surah details the stories of several prophets, including Adam, Noah, Hud, Salih, Lot, and Moses, emphasizing the consequences for those who reject their message. It describes the dialogue between the inhabitants of Paradise, Hell, and the "heights" (Al-A'raf).
        </SummaryCard>
      </main>
    </div>
  );
}
